changeSet.sql:
-- Bills CREATE TABLE IF NOT EXISTS bills ( id bigint not null, account_id BIGINT not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, bill_number VARCHAR(50) UNIQUE NOT NULL, partner_id INTEGER , bill_date DATE NOT NULL, due_date DATE NOT NULL, description TEXT, status VARCHAR(20) NOT NULL, total_amount DECIMAL(15,2) NOT NULL, journal_entry_id INTEGER REFERENCES journal_entries(id) , CONSTRAINT bills_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS bills_id_seq INCREMENT 1 START 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1 OWNED BY bills.id;
CREATE TABLE IF NOT EXISTS bill_lines ( id bigint not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, bill_id bigint REFERENCES bills(id), description TEXT NOT NULL, quantity DECIMAL(15,2) NOT NULL, unit_price DECIMAL(15,2) NOT NULL, amount DECIMAL(15,2) NOT NULL, CONSTRAINT app_bill_lines_p_key PRIMARY KEY (id), fin_account_id INTEGER REFERENCES fin_accounts(id) );
CREATE SEQUENCE IF NOT EXISTS bill_lines_id_seq INCREMENT 1 START 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1 OWNED BY bill_lines.id;
